sub build_article_html {
  my $sections = shift;
  my $html = "\n";
  for my $sec (@$sections) {
    $html .= "    <h3>$sec->{h}</h3>\n    <p>$sec->{p}</p>\n\n";
  }
  return $html;
}

for my $file (sort keys %articles) {
  my $sections = $articles{$file};

  open my $fh, '<:encoding(UTF-8)', $file or do { warn "Cannot read $file: $!\n"; next };
  local $/;
  my $html = <$fh>;
  close $fh;

  # Remove existing long-form article markers if present (re-run safe)
  $html =~ s|\s*<!-- LONGFORM_START -->.*?<!-- LONGFORM_END -->||s;

  my $article = "    <!-- LONGFORM_START -->" . build_article_html($sections) . "    <!-- LONGFORM_END -->\n";

  # Insert the article AFTER the intro <p> (the one right after <h2> in .tool-seo)
  # and BEFORE the <h3>วิธีใช้งาน</h3>
  $html =~ s|(<section class="tool-seo">\s*<h2>[^<]+</h2>\s*<p>.*?</p>)(\s*<h3>วิธีใช้งาน</h3>)|$1\n\n$article$2|s;

  open my $out, '>:encoding(UTF-8)', $file or die "Cannot write $file: $!\n";
  print $out $html;
  close $out;

  print "OK: $file\n";
}
